+/// Binary search: leftmost insertion position (lower_bound) for f32.
+fn lower_bound_f32(sorted: &[f32], value: f32, n: usize) -> usize {
+    let mut lo = 0usize;
+    let mut hi = n;
+    while lo < hi {
+        let mid = lo + (hi - lo) / 2;
+        if sorted[mid] < value {
+            lo = mid + 1;
+        } else {
+            hi = mid;
+        }
+    }
+    lo
+}
